<?php
/**
 * Setup du thème — constantes, WooCommerce coming soon, utilitaires.
 */

if (! defined('ABSPATH')) {
    exit;
}

/**
 * Désactiver le mode "Coming Soon" de WooCommerce (>= 9.1).
 */
add_filter('woocommerce_coming_soon_exclude', function () {
    return true;
}, 10);
add_action('admin_bar_menu', function ($wp_admin_bar) {
    $wp_admin_bar->remove_node('woocommerce-site-visibility-badge');
}, 100);
update_option('woocommerce_coming_soon', 'no');

/**
 * Petit utilitaire : version basée sur filemtime pour le cache-busting.
 */
function dm_asset_ver($relative_path)
{
    $file = DM_THEME_DIR . '/' . ltrim($relative_path, '/');
    return file_exists($file) ? filemtime($file) : '1.0.0';
}

